    ```


    @removed(Versions.`2025-12-01-preview`)

    @renamedFrom(Versions.`2025-12-01-preview`, "createOrReplaceWidget")

    createOrReplaceWidgetV1isOperations.ResourceCreateOrReplace<Widget>;

    @added(Versions.`2025-12-01-preview`)

    getWidgetOperationStatusisOperations.GetResourceOperationStatus<Widget, never>;

    @added(Versions.`2025-12-01-preview`)

    @pollingOperation(Widgets.getWidgetOperationStatus)

