Get-ChildItem $dst -Filter "*.json" | ForEach-Object {
    $json = Get-Content $_.FullName -Raw | ConvertFrom-Json -Depth 20

    # Function to remove workLocation recursively
    function Remove-WorkLocation($obj) {
        if ($null -eq $obj) { return }
        if ($obj -is [System.Management.Automation.PSCustomObject]) {
            $props = @($obj.PSObject.Properties.Name)
            foreach ($prop in $props) {
                if ($prop -eq 'workLocation') {
                    $obj.PSObject.Properties.Remove('workLocation')
                } else {
                    Remove-WorkLocation $obj.$prop
                }
            }
        } elseif ($obj -is [System.Collections.IEnumerable] -and $obj -isnot [string]) {
            foreach ($item in $obj) {
                Remove-WorkLocation $item
            }
        }
    }

    Remove-WorkLocation $json
    $json | ConvertTo-Json -Depth 20 | Set-Content $_.FullName -NoNewline
    Write-Host "Processed $($_.Name)"
}

